// src/pages/DashboardPage.js
import React, { useEffect, useState } from "react";
import { getSessions } from "../utils/firebase";
import "./DashboardPage.css";

// ── Donut chart for Overall Progress ──────────────────────────────────────────
function DonutChart({ percent, color = "#7c6fcd" }) {
  const r = 44;
  const circ = 2 * Math.PI * r;
  const dash = (percent / 100) * circ;
  return (
    <svg width="110" height="110" viewBox="0 0 110 110">
      <circle cx="55" cy="55" r={r} fill="none" stroke="#ede9ff" strokeWidth="10" />
      <circle
        cx="55" cy="55" r={r} fill="none"
        stroke={color} strokeWidth="10"
        strokeDasharray={`${dash} ${circ}`}
        strokeLinecap="round"
        transform="rotate(-90 55 55)"
        style={{ transition: "stroke-dasharray 1s ease" }}
      />
      <text x="55" y="58" textAnchor="middle" fontSize="18" fontWeight="800"
        fill="#1a1a2e" fontFamily="'Nunito',sans-serif">{percent}%</text>
    </svg>
  );
}

// ── Mini bar chart ──────────────────────────────────────────────────────────
function MiniChart({ sessions, field, color, label }) {
  if (!sessions.length) return null;
  const vals = sessions.map((s) => s.metrics?.[field] ?? 0).reverse();
  const max = Math.max(...vals, 1);
  return (
    <div className="mini-chart">
      <span className="mini-chart-label">{label}</span>
      <div className="mini-chart-bars">
        {vals.map((v, i) => (
          <div key={i} className="mini-chart-bar-wrap" title={v}>
            <div className="mini-chart-bar" style={{ height: `${(v / max) * 100}%`, background: color }} />
          </div>
        ))}
      </div>
    </div>
  );
}

// ── Sidebar nav item ────────────────────────────────────────────────────────
function NavItem({ icon, label, active, onClick }) {
  return (
    <button className={`sidenav-item ${active ? "active" : ""}`} onClick={onClick}>
      <span className="sidenav-icon">{icon}</span>
      <span className="sidenav-label">{label}</span>
    </button>
  );
}

// ── Weekly streak days ──────────────────────────────────────────────────────
const DAYS = ["M", "T", "W", "T", "F", "S", "S"];

export default function DashboardPage({ navigate, user, onLogout }) {
  const [sessions, setSessions] = useState([]);
  const [loading, setLoading]   = useState(true);
  const [activeNav, setActiveNav] = useState("home");

  useEffect(() => {
    getSessions(20).then((data) => {
      setSessions(data);
      setLoading(false);
    });
  }, []);

  const avg = (field) => {
    if (!sessions.length) return 0;
    return Math.round(sessions.reduce((acc, s) => acc + (s.metrics?.[field] ?? 0), 0) / sessions.length);
  };

  const best = sessions.reduce(
    (b, s) => (!b || (s.metrics?.score ?? 0) > (b.metrics?.score ?? 0)) ? s : b,
    null
  );

  // Compute overall progress score (avg of score as a percent)
  const overallProgress = avg("score") || 0;

  // Most recent session for "Continue your practice"
  const recent = sessions[0] || null;

  // Weekly streak: simulate 7 days, marking Mon–Sat as done (last day pending)
  const streakDays = [true, true, true, true, true, true, false];
  const streakCount = streakDays.filter(Boolean).length;

  const displayName = user?.displayName || user?.email?.split("@")[0] || "there";
  const initials = displayName.slice(0, 2).toUpperCase();

  return (
    <div className="db-root">
      {/* ── SIDEBAR ─────────────────────────────────────────────────────── */}
      <aside className="db-sidebar">
        {/* Logo */}
        <div className="db-sidebar-logo" onClick={() => navigate("landing")}>
          <div className="db-logo-icon">
            <svg viewBox="0 0 40 40" fill="none" xmlns="http://www.w3.org/2000/svg" width="22" height="22">
              <defs>
                <linearGradient id="lg1" x1="0%" y1="0%" x2="100%" y2="100%">
                  <stop offset="0%" stopColor="#a99dff"/>
                  <stop offset="100%" stopColor="#7c6fcd"/>
                </linearGradient>
              </defs>
              <path d="M28 10C25.3 7.3 21.8 5.5 18 5.5C10.5 5.5 4.5 11.5 4.5 19C4.5 26.5 10.5 32.5 18 32.5C21.8 32.5 25.3 30.7 28 28"
                stroke="url(#lg1)" strokeWidth="4" strokeLinecap="round"/>
              <path d="M32 9 L33.2 12 L36 13 L33.2 14 L32 17 L30.8 14 L28 13 L30.8 12 Z" fill="url(#lg1)"/>
            </svg>
          </div>
          <span className="db-logo-text">CLARIO</span>
          <span className="db-logo-sub">AI SPEECH COACH</span>
        </div>

        {/* Nav items */}
        <nav className="db-sidenav">
          <NavItem icon={
            <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
              <path d="M3 9.5L12 3l9 6.5V20a1 1 0 01-1 1H4a1 1 0 01-1-1V9.5z"/>
              <path d="M9 21V12h6v9"/>
            </svg>
          } label="Home" active={activeNav === "home"} onClick={() => setActiveNav("home")} />

          <NavItem icon={
            <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
              <path d="M12 1a3 3 0 013 3v8a3 3 0 01-6 0V4a3 3 0 013-3z"/>
              <path d="M19 10a7 7 0 01-14 0M12 19v4M8 23h8"/>
            </svg>
          } label="Practice" active={activeNav === "practice"} onClick={() => { setActiveNav("practice"); navigate("practice"); }} />

          <NavItem icon={
            <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
              <rect x="3" y="3" width="7" height="7" rx="1"/><rect x="14" y="3" width="7" height="7" rx="1"/>
              <rect x="3" y="14" width="7" height="7" rx="1"/><rect x="14" y="14" width="7" height="7" rx="1"/>
            </svg>
          } label="Scenarios" active={activeNav === "scenarios"} onClick={() => setActiveNav("scenarios")} />

          <NavItem icon={
            <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
              <polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/>
            </svg>
          } label="Progress" active={activeNav === "progress"} onClick={() => setActiveNav("progress")} />

          <div className="sidenav-divider" />

          <NavItem icon={
            <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
              <circle cx="12" cy="12" r="3"/>
              <path d="M19.07 4.93a10 10 0 010 14.14M4.93 4.93a10 10 0 000 14.14"/>
            </svg>
          } label="Settings" active={activeNav === "settings"} onClick={() => setActiveNav("settings")} />

          <NavItem icon={
            <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
              <path d="M17 16l4-4-4-4M21 12H9M13 4H5a2 2 0 00-2 2v12a2 2 0 002 2h8"/>
            </svg>
          } label="Log out" active={false} onClick={onLogout} />
        </nav>

        {/* Premium upsell */}
        <div className="db-premium-box">
          <div className="db-premium-crown">👑</div>
          <p className="db-premium-title">Go Premium</p>
          <p className="db-premium-desc">Unlock advanced insights, personalized tips, and unlimited practice.</p>
          <button className="db-premium-btn">Upgrade Now</button>
        </div>

        {/* Sidebar wave decoration */}
        <div className="db-sidebar-wave">
          <svg viewBox="0 0 220 80" preserveAspectRatio="none">
            <path d="M0 40 Q55 0 110 40 Q165 80 220 40 L220 80 L0 80 Z" fill="rgba(124,108,252,0.12)"/>
          </svg>
        </div>
      </aside>

      {/* ── MAIN AREA ───────────────────────────────────────────────────── */}
      <div className="db-main">
        {/* Top header */}
        <header className="db-topbar">
          <div />
          <div className="db-topbar-right">
            <button className="db-notif-btn" aria-label="Notifications">
              <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
                <path d="M18 8A6 6 0 006 8c0 7-3 9-3 9h18s-3-2-3-9M13.73 21a2 2 0 01-3.46 0"/>
              </svg>
              <span className="db-notif-dot" />
            </button>
            <div className="db-user-pill">
              <div className="db-user-avatar">{initials}</div>
              <div className="db-user-info">
                <span className="db-user-name">{displayName}</span>
                <span className="db-user-role">Student</span>
              </div>
              <svg width="14" height="14" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2" style={{color:"#9090b0"}}>
                <polyline points="6 9 12 15 18 9"/>
              </svg>
            </div>
          </div>
        </header>

        {/* Page content */}
        <div className="db-content">
          {loading ? (
            <div className="dash-loading">
              <div className="spinner" />
              <p>Loading your dashboard…</p>
            </div>
          ) : (
            <>
              {/* ── Hero greeting + right column ── */}
              <div className="db-hero-row">
                {/* Left: greeting + hero card + recent + tip */}
                <div className="db-center-col">
                  <div className="db-greeting">
                    <h1>Hello, {displayName.split(" ")[0]}! 👋</h1>
                    <p>Ready to speak with confidence today?</p>
                  </div>

                  {/* Hero banner */}
                  <div className="db-hero-banner">
                    <div className="db-hero-text">
                      <h2>Start a Practice Session</h2>
                      <p>Choose a scenario, record your speech, and get AI-powered feedback to improve.</p>
                      <button className="db-hero-btn" onClick={() => navigate("practice")}>
                        Start Practice <span>→</span>
                      </button>
                    </div>
                    <div className="db-hero-visual">
                      <div className="db-hero-card-float">
                        <div className="db-hero-waveform">
                          {[...Array(9)].map((_, i) => (
                            <div key={i} className="db-hero-bar"
                              style={{ "--h": `${28 + Math.sin(i * 0.9) * 22}px`, "--d": `${i * 0.1}s` }} />
                          ))}
                        </div>
                        <div className="db-hero-play">▶</div>
                      </div>
                      <div className="db-hero-bubble db-bubble-pink">
                        <svg width="16" height="16" fill="white" viewBox="0 0 24 24">
                          <path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"/>
                        </svg>
                      </div>
                    </div>
                  </div>

                  {/* Continue your practice */}
                  <div className="db-continue-section">
                    <div className="db-section-header">
                      <h3>Continue your practice</h3>
                      <button className="db-link-btn" onClick={() => navigate("dashboard")}>View all history →</button>
                    </div>

                    {sessions.length === 0 ? (
                      <div className="db-no-sessions">
                        <span>🎙️</span>
                        <p>No sessions yet — start your first one above!</p>
                      </div>
                    ) : (
                      <div className="db-session-list">
                        {sessions.slice(0, 3).map((s, i) => {
                          const pct = Math.min(100, Math.round((s.metrics?.score ?? 0)));
                          return (
                            <div key={s.id || i} className="db-session-card">
                              <div className="db-session-icon">
                                {s.scenario?.includes("Interview") ? "💼"
                                  : s.scenario?.includes("Thesis") ? "🎓"
                                  : s.scenario?.includes("Recitation") ? "📖" : "🎤"}
                              </div>
                              <div className="db-session-info">
                                <p className="db-session-title">{s.scenario || "General Speaking"}</p>
                                <p className="db-session-sub">
                                  {s.date ? new Date(s.date).toLocaleDateString("en-PH", { month: "long", day: "numeric" }) : "—"}
                                </p>
                                <div className="db-session-progress-track">
                                  <div className="db-session-progress-fill" style={{ width: `${pct}%` }} />
                                </div>
                                <p className="db-session-pct">{pct}% completed</p>
                              </div>
                              <div className="db-session-metrics">
                                <div className="db-sm"><span className="db-sm-icon">🕐</span><b>{s.metrics?.duration ? `${Math.floor(s.metrics.duration / 60)} min` : "—"}</b><span>Duration</span></div>
                                <div className="db-sm"><span className="db-sm-icon">〰️</span><b>{s.metrics?.wpm ?? "—"}</b><span>WPM</span></div>
                                <div className="db-sm"><span className="db-sm-icon">💬</span><b>{s.metrics?.totalFillers ?? "—"}</b><span>Fillers</span></div>
                                <div className="db-sm"><span className="db-sm-icon">⭐</span><b>{s.metrics?.score ?? "—"}/100</b><span>Score</span></div>
                              </div>
                              <button className="db-continue-btn" onClick={() => navigate("practice")}>Continue</button>
                            </div>
                          );
                        })}
                      </div>
                    )}
                  </div>

                  {/* Tip of the day */}
                  <div className="db-tip-card">
                    <div className="db-tip-icon">💡</div>
                    <div className="db-tip-body">
                      <p className="db-tip-title">Tip of the day</p>
                      <p className="db-tip-text">Pause for effect. Short pauses help your ideas land and keep your listeners engaged.</p>
                    </div>
                    <button className="db-link-btn" style={{ flexShrink: 0 }}>View more tips →</button>
                  </div>
                </div>

                {/* Right column: progress + streak */}
                <div className="db-right-col">
                  {/* Overall Progress */}
                  <div className="db-widget-card">
                    <h4 className="db-widget-title">Overall Progress</h4>
                    <div className="db-donut-row">
                      <DonutChart percent={overallProgress} />
                      <div className="db-donut-info">
                        <p className="db-donut-label">
                          {overallProgress >= 80 ? "Excellent work!" : overallProgress >= 60 ? "You're doing great!" : "Keep it up!"}
                        </p>
                        <p className="db-donut-sub">Keep practicing to reach your goal.</p>
                      </div>
                    </div>
                    <button className="db-link-btn" style={{ fontSize: 13, marginTop: 8 }}>View detailed progress →</button>
                  </div>

                  {/* Weekly Streak */}
                  <div className="db-widget-card">
                    <h4 className="db-widget-title">Weekly Streak</h4>
                    <div className="db-streak-top">
                      <span className="db-streak-fire">🔥</span>
                      <div>
                        <p className="db-streak-count">{streakCount} days</p>
                        <p className="db-streak-sub">Great consistency!</p>
                      </div>
                    </div>
                    <div className="db-streak-days">
                      {DAYS.map((d, i) => (
                        <div key={i} className="db-streak-day">
                          <div className={`db-streak-dot ${streakDays[i] ? "done" : "empty"}`}>
                            {streakDays[i] && (
                              <svg width="10" height="10" viewBox="0 0 10 10" fill="none">
                                <path d="M2 5l2 2 4-4" stroke="white" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                              </svg>
                            )}
                          </div>
                          <span className="db-streak-day-label">{d}</span>
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Quick stats */}
                  {sessions.length > 0 && (
                    <div className="db-widget-card">
                      <h4 className="db-widget-title">Your Averages</h4>
                      <div className="db-quick-stats">
                        <div className="db-qs-item">
                          <span className="db-qs-val" style={{ color: "#7c6fcd" }}>{sessions.length}</span>
                          <span className="db-qs-label">Sessions</span>
                        </div>
                        <div className="db-qs-item">
                          <span className="db-qs-val" style={{ color: "#4ecca3" }}>{avg("score")}</span>
                          <span className="db-qs-label">Avg Score</span>
                        </div>
                        <div className="db-qs-item">
                          <span className="db-qs-val" style={{ color: "#ffd166" }}>{avg("wpm")}</span>
                          <span className="db-qs-label">Avg WPM</span>
                        </div>
                        <div className="db-qs-item">
                          <span className="db-qs-val" style={{ color: "#fc6c8f" }}>{avg("totalFillers")}</span>
                          <span className="db-qs-label">Avg Fillers</span>
                        </div>
                      </div>

                      {/* Mini trends */}
                      <div style={{ marginTop: 16, display: "flex", flexDirection: "column", gap: 10 }}>
                        <MiniChart sessions={sessions} field="score" color="#7c6fcd" label="Score trend" />
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
